let cardScreenId=null;
function renderCards(){
  if(!cardScreenId || !screenById(cardScreenId)) cardScreenId=S.screens[0]?.id||null;
  const sel=document.getElementById('cardScreen'); sel.innerHTML=S.screens.map(s=>`<option value="${s.id}" ${s.id===cardScreenId?'selected':''}>${esc(s.name)}</option>`).join('');
  const scr=screenById(cardScreenId), cls=screenClasses(scr), t=document.getElementById('cardsTable');
  const cc=document.getElementById('cardClasses');
  if(cc){
    if(!scr){ cc.innerHTML=''; }
    else { cc.innerHTML=`<div class="muted" style="margin-bottom:6px">Tick the combination of classes <b>${esc(scr.name)}</b> uses — the price-card columns below follow this selection. (Seat counts are set in Screens &amp; Tax.)</div>`
      + (S.classes.length? S.classes.map(c=>{ const on=(scr.classes||[]).some(a=>a.classId===c.id);
          return `<label style="display:inline-flex;align-items:center;gap:6px;margin:0 16px 6px 0;font-weight:600"><input type="checkbox" data-clstoggle="${c.id}" ${on?'checked':''}> ${esc(c.name)}</label>`; }).join('')
        : '<span class="muted">No classes in the catalog yet — add some in Screens &amp; Tax.</span>'); }
  }
  if(!scr){ t.innerHTML=`<tr><td class="empty-state">Add a screen first (Screens &amp; Tax).</td></tr>`; return; }
  if(!cls.length){ t.innerHTML=`<tr><td class="empty-state">This screen has no classes assigned — assign some in Screens &amp; Tax.</td></tr>`; return; }
  t.innerHTML=`<thead><tr><th>Card name</th>${cls.map(c=>`<th>${esc(c.name)} (gross ₹)</th>`).join('')}<th></th></tr></thead>
    <tbody>${(scr.priceCards||[]).map(c=>`<tr data-id="${c.id}"><td><input data-f="name" value="${esc(c.name)}"></td>
      ${cls.map(cl=>`<td><input type="number" data-price="${cl.classId}" step="0.01" value="${c.prices[cl.classId]??''}"></td>`).join('')}
      <td class="center"><button class="btn danger sm" data-del="${c.id}">Delete</button></td></tr>`).join('')
      ||`<tr><td colspan="${cls.length+2}" class="empty-state">No cards yet.</td></tr>`}</tbody>`;
}
