// ====================== BULK CSV UPLOAD ======================
function parseCsv(text){
  text=String(text).replace(/^﻿/,''); const rows=[]; let row=[],cell='',q=false;
  for(let i=0;i<text.length;i++){ const c=text[i];
    if(q){ if(c==='"'){ if(text[i+1]==='"'){cell+='"';i++;} else q=false; } else cell+=c; }
    else if(c==='"') q=true;
    else if(c===','){ row.push(cell); cell=''; }
    else if(c==='\n'||c==='\r'){ if(c==='\r'&&text[i+1]==='\n') i++; row.push(cell); rows.push(row); row=[]; cell=''; }
    else cell+=c;
  }
  if(cell!==''||row.length){ row.push(cell); rows.push(row); }
  return rows.filter(r=>!(r.length===1 && String(r[0]).trim()===''));
}
function bulkClassCols(){ return (S.classes||[]).map(c=>c.name); }
function bulkParseDate(v){ v=String(v).trim(); if(!v) return null;
  let m=v.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/); if(m) return m[1]+'-'+m[2].padStart(2,'0')+'-'+m[3].padStart(2,'0');
  m=v.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/); if(m) return m[3]+'-'+m[2].padStart(2,'0')+'-'+m[1].padStart(2,'0');
  return null; }
function bulkParseTime(v){ v=String(v).trim(); if(!v) return ''; let ap=null; const mm=v.match(/(am|pm)$/i); if(mm){ ap=mm[1].toLowerCase(); v=v.replace(/\s*(am|pm)$/i,'').trim(); }
  const p=v.split(':'); let h=parseInt(p[0],10), mn=p[1]!=null?parseInt(p[1],10):0; if(isNaN(h)) return null; if(ap==='pm'&&h<12)h+=12; if(ap==='am'&&h===12)h=0;
  if(h<0||h>23||isNaN(mn)||mn<0||mn>59) return null; return String(h).padStart(2,'0')+':'+String(mn).padStart(2,'0'); }
function bulkTemplate(){
  const classes=bulkClassCols();
  const header=['Date','Movie','Screen','Showtime','Price Card'].concat(classes).concat(['Online','Free Pass','Last Show']);
  const rows=[header];
  rows.push(['# One row per show. Rows with the same Date + Movie + Screen become one day. Date = YYYY-MM-DD. Showtime = HH:MM (24h). Price Card must match a card name for that screen. Leave a class blank if that screen does not use it. Last Show = yes on the movie’s final show of the day.']);
  rows.push(['# Movies: '+S.movies.map(m=>m.name).join(', ')]);
  rows.push(['# Screens & cards: '+S.screens.map(sc=>sc.name+' ['+cardsOf(sc.id).map(c=>c.name).join(', ')+']').join('   |   ')]);
  const m0=S.movies[0], sc0=S.screens[0], cd0=cardsOf(sc0?sc0.id:'')[0];
  if(m0&&sc0&&cd0){ const ex=['2026-05-22',m0.name,sc0.name,'10:45',cd0.name]; classes.forEach(cn=>{ const cl=screenClasses(sc0).find(c=>c.name===cn); ex.push(cl?'0':''); }); ex.push('','','no'); rows.push(ex); }
  downloadCsv('DCR_bulk_template.csv', rows);
}
function bulkSample(){
  const classes=bulkClassCols();
  const header=['Date','Movie','Screen','Showtime','Price Card'].concat(classes).concat(['Online','Free Pass','Last Show']);
  const rows=[header];
  const mv=(S.movies[0]||{name:'Movie'}), sc=(S.screens[0]||{name:''}), cards=cardsOf(sc.id||''), scCls=screenClasses(sc);
  const cardName=i=> ((cards.length?cards[i%cards.length]:null)||{name:''}).name;
  const times=['10:45','14:00','17:45','21:00'], base=[20,150,300,120,200];
  ['2026-05-22','2026-05-23'].forEach(function(date,di){
    times.forEach(function(t,si){
      const r=[date, mv.name, sc.name, t, cardName(si)];
      classes.forEach(function(cn){ const pos=scCls.findIndex(c=>c.name===cn); if(pos<0){ r.push(''); return; } r.push(String(Math.max(0,(base[pos]||0)-si*8+di*5))); });
      r.push((si===0||si===times.length-1)?String(90000+si*9000+di*4000):'');
      r.push('');
      r.push(si===times.length-1?'yes':'no');
      rows.push(r);
    });
  });
  downloadCsv('DCR_bulk_sample_filled.csv', rows);
}
var bulkPending=null;
function validateBulk(rows){
  const errors=[]; if(!rows.length) return {errors:['The file is empty.']};
  const header=rows[0].map(h=>String(h).trim()); const idx={}; header.forEach((h,i)=>{ idx[h.toLowerCase()]=i; });
  ['date','movie','screen','showtime','price card'].forEach(n=>{ if(idx[n]==null) errors.push('Missing required column: "'+n+'"'); });
  if(errors.length) return {errors};
  const classes=bulkClassCols(); const norm=s=>String(s||'').trim().toLowerCase(); const digits=s=>String(s||'').replace(/\D/g,'');
  const map={};
  for(let r=1;r<rows.length;r++){
    const row=rows[r]; if(!row.length) continue; if(String(row[0]).trim().startsWith('#')) continue;
    if(row.every(c=>String(c).trim()==='')) continue;
    const ln=r+1, get=name=> (idx[name]!=null ? String(row[idx[name]]||'').trim() : '');
    const date=bulkParseDate(get('date')); if(!date){ errors.push('Row '+ln+': bad/blank date "'+get('date')+'"'); continue; }
    const mv=S.movies.find(m=>norm(m.name)===norm(get('movie'))); if(!mv){ errors.push('Row '+ln+': unknown movie "'+get('movie')+'"'); continue; }
    const sc=S.screens.find(s=>norm(s.name)===norm(get('screen'))); if(!sc){ errors.push('Row '+ln+': unknown screen "'+get('screen')+'"'); continue; }
    const time=bulkParseTime(get('showtime')); if(time===null){ errors.push('Row '+ln+': bad showtime "'+get('showtime')+'"'); continue; }
    const card=cardsOf(sc.id).find(c=>norm(c.name)===norm(get('price card')) || (digits(get('price card'))&&digits(c.name)===digits(get('price card'))));
    if(!card){ errors.push('Row '+ln+': price card "'+get('price card')+'" not found for screen '+sc.name); continue; }
    const scCls=screenClasses(sc), rowsObj={};
    classes.forEach(cn=>{ if(idx[cn.toLowerCase()]==null) return; const val=String(row[idx[cn.toLowerCase()]]||'').trim(); if(val==='') return;
      const cl=scCls.find(c=>norm(c.name)===norm(cn)); if(!cl){ errors.push('Row '+ln+': class "'+cn+'" is not on screen '+sc.name); return; }
      rowsObj[cl.classId]={tickets:String(N(val))}; });
    const last=['yes','y','true','1'].indexOf(norm(get('last show')))>=0;
    const show={id:uid(), showtime:time, priceCardId:card.id, freePass:get('free pass'), online:get('online'), lastShow:last, rows:rowsObj};
    const key=date+'|'+mv.id+'|'+sc.id;
    if(!map[key]) map[key]={date, movieId:mv.id, screenId:sc.id, share:N(mv.share), shows:[]};
    map[key].shows.push(show);
  }
  if(errors.length) return {errors};
  const entries=Object.values(map); let nw=0,upd=0;
  entries.forEach(e=>{ S.entries.find(x=>x.date===e.date&&x.movieId===e.movieId&&x.screenId===e.screenId)?upd++:nw++; });
  return {errors:[], entries, rowCount:entries.reduce((a,e)=>a+e.shows.length,0), days:entries.length, nw, upd};
}
function bulkShowPreview(res){
  const pv=document.getElementById('bulkPreview'), btn=document.getElementById('bulkImport');
  if(res.errors&&res.errors.length){ bulkPending=null; btn.style.display='none';
    pv.innerHTML='<b style="color:var(--red)">Found '+res.errors.length+' problem(s) — fix the file and upload again:</b><br>'+res.errors.slice(0,40).map(esc).join('<br>'); return; }
  bulkPending=res.entries;
  const lines=res.entries.map(e=>{ const m=S.movies.find(x=>x.id===e.movieId), s=S.screens.find(x=>x.id===e.screenId);
    return e.date+'  ·  '+(m?m.name:'?')+'  ·  '+(s?s.name:'?')+'  ('+e.shows.length+' show'+(e.shows.length>1?'s':'')+')'; });
  pv.innerHTML='<b style="color:var(--blue)">Ready to import:</b> '+res.rowCount+' shows across '+res.days+' day(s) — '+res.nw+' new, '+res.upd+' will update existing.<br>'+lines.map(esc).join('<br>');
  btn.style.display='';
}
function bulkDoImport(){
  if(!bulkPending) return;
  bulkPending.forEach(e=>{ const ex=S.entries.find(x=>x.date===e.date&&x.movieId===e.movieId&&x.screenId===e.screenId);
    if(ex){ ex.shows=e.shows; ex.share=e.share; } else { S.entries.push({id:uid(), date:e.date, movieId:e.movieId, screenId:e.screenId, share:e.share, shows:e.shows}); } });
  save(); const n=bulkPending.length; bulkPending=null;
  document.getElementById('bulkImport').style.display='none';
  document.getElementById('bulkPreview').innerHTML='<b style="color:var(--blue)">Imported '+n+' day(s).</b> Open the History tab to see them.';
  renderEntries();
}
document.getElementById('bulkTemplate').onclick=bulkTemplate;
document.getElementById('bulkSample').onclick=bulkSample;
document.getElementById('bulkUpload').onclick=()=>document.getElementById('bulkFile').click();
document.getElementById('bulkFile').addEventListener('change',e=>{ const f=e.target.files[0]; if(!f) return; const rd=new FileReader();
  rd.onload=()=>{ try{ bulkShowPreview(validateBulk(parseCsv(rd.result))); }catch(err){ document.getElementById('bulkPreview').textContent='Could not read that CSV: '+err.message; } e.target.value=''; }; rd.readAsText(f); });
document.getElementById('bulkImport').onclick=bulkDoImport;

// ====================== HISTORY (fetch past DCRs) ======================
let histFilter={movie:'',from:'',to:''};
function renderHistory(){
  const mv=document.getElementById('h_movie');
  mv.innerHTML='<option value="">All movies</option>'+S.movies.map(m=>`<option value="${m.id}">${esc(m.name)}</option>`).join('');
  mv.value=histFilter.movie||'';
  document.getElementById('h_from').value=histFilter.from||'';
  document.getElementById('h_to').value=histFilter.to||'';
  let rows=[...S.entries];
  if(histFilter.movie) rows=rows.filter(e=>e.movieId===histFilter.movie);
  if(histFilter.from) rows=rows.filter(e=>(e.date||'')>=histFilter.from);
  if(histFilter.to) rows=rows.filter(e=>(e.date||'')<=histFilter.to);
  rows.sort((a,b)=>(b.date||'').localeCompare(a.date||''));
  const t=document.getElementById('historyTable');
  t.innerHTML=`<thead><tr><th>Date</th><th>Movie</th><th>Screen</th><th>Shows</th><th>Audience</th><th>Gross</th><th></th></tr></thead>
    <tbody>${rows.map(e=>{ const c=computeShallow(e), m=S.movies.find(x=>x.id===e.movieId), s=screenById(e.screenId);
      return `<tr><td>${e.date||''}</td><td>${esc(m?.name||'?')}</td><td>${esc(s?.name||'?')}</td><td class="center">${(e.shows||[]).length}</td>
        <td class="right">${int(c.audience)}</td><td class="right">₹${money(c.grossColl)}</td>
        <td class="center"><button class="btn sm" data-view="${e.id}">View DCR</button> <button class="btn ghost sm" data-tally="${e.id}" title="Download Tally CSV for this DCR">Tally CSV</button> <button class="btn danger sm acct-hide" data-del="${e.id}">Delete</button></td></tr>`;}).join('')
      ||`<tr><td colspan="7" class="empty-state">No saved DCRs match these filters.</td></tr>`}</tbody>`;
}
document.getElementById('h_movie').addEventListener('change',e=>{ histFilter.movie=e.target.value; renderHistory(); });
document.getElementById('h_from').addEventListener('change',e=>{ histFilter.from=e.target.value; renderHistory(); });
document.getElementById('h_to').addEventListener('change',e=>{ histFilter.to=e.target.value; renderHistory(); });
document.getElementById('h_clear').onclick=()=>{ histFilter={movie:'',from:'',to:''}; renderHistory(); };
document.getElementById('historyTable').addEventListener('click',e=>{
  if(e.target.dataset.view){ const en=S.entries.find(x=>x.id===e.target.dataset.view); if(en){
    // Accountants: render a read-only DCR view by computing without setting draft
    if(window.__DCR_ROLE==='accountant'){
      var C = computeEntry(en);
      if(!C.movie || !C.screen){ alert('Movie or screen missing for this DCR.'); return; }
      document.querySelector('#tabnav button[data-tab="entry"]').click();
      renderDCR(C);
      return;
    }
    S.draft=JSON.parse(JSON.stringify(en)); save();
    document.querySelector('#tabnav button[data-tab="entry"]').click(); renderDCR(computeEntry(S.draft));
  } }
  if(e.target.dataset.tally){
    var idT = e.target.dataset.tally;
    var en = S.entries.find(x=>x.id===idT);
    if(!en){ return; }
    var C = computeEntry(en);
    if(!C.movie || !C.screen){ alert('Movie or screen info missing — cannot build Tally CSV for this DCR.'); return; }
    var rows = tallyCsvRows(C);
    if(rows.length<2){ alert('No sold tickets with serials on this DCR.'); return; }
    downloadCsv('Tally_'+((C.movie.name||'movie').replace(/\s+/g,'_'))+'_'+((C.entry||{}).date||en.date||'')+'.csv', rows);
  }
  if(e.target.dataset.del){ if(window.__DCR_ROLE==='accountant'){ return; } var _en=S.entries.find(x=>x.id===e.target.dataset.del); if(!confirm('Delete this DCR'+(_en&&_en.date?(' for '+_en.date):'')+' permanently? It will be removed from the cloud for everyone and cannot be undone.')) return; S.entries=S.entries.filter(x=>x.id!==e.target.dataset.del); save(); renderHistory(); }
});

// ---------- boot ----------
renderEntry();
